import*as Browser from"@hyperjump/browser";import*as Instance from"../instance.js";import{getKeywordName}from"../experimental.js";const id="https://json-schema.org/keyword/requireAllExcept",compile=async(e,r,t)=>{const o=await Browser.value(e);e=getKeywordName(e.document.dialectId,"https://json-schema.org/keyword/properties"),e=await Browser.step(e,t);const s="object"===Browser.typeOf(e)?Browser.keys(e):[];t=new Set(s);return o.forEach(e=>s.remove(e)),[...t]},interpret=(e,r)=>"object"!==Instance.typeOf(r)||e.every(e=>Object.hasOwn(Instance.value(r),e));export default{id:id,compile:compile,interpret:interpret};